  1→/* ── Content Viewer — Notion-inspired redesign ── */
  2→
  3→/* ── Loading ── */
  4→.cv-loading {
  5→    display: flex;
  6→    justify-content: center;
  7→    align-items: center;
  8→    width: 100%;
  9→    height: 100vh;
 10→    background-color: var(--bg-primary);
 11→}
 12→
 13→/* ── Container ── */
 14→.cv-container {
 15→    position: relative;
 16→    display: flex;
 17→    flex-direction: column;
 18→    align-items: center;
 19→    width: 100%;
 20→    min-height: 100vh;
 21→    background-color: var(--bg-primary);
 22→    overflow-y: auto;
 23→}
 24→.cv-container::-webkit-scrollbar {
 25→    display: none;
 26→    width: 0;
 27→    height: 0;
 28→}
 29→
 30→/* ── Back header ── */
 31→.cv-header {
 32→    position: fixed;
 33→    top: 0;
 34→    display: flex;
 35→    align-items: center;
 36→    gap: 10px;
 37→    width: 100%;
 38→    max-width: 720px;
 39→    height: 44px;
 40→    padding: 0 16px;
 41→    box-sizing: border-box;
 42→    background: var(--bg-primary);
 43→    border-bottom: 1px solid var(--border-light);
 44→    z-index: 10;
 45→    user-select: none;
 46→}
 47→.cv-back-btn {
 48→    display: flex;
 49→    justify-content: center;
 50→    align-items: center;
 51→    width: 28px;
 52→    height: 28px;
 53→    border-radius: 4px;
 54→    background: transparent;
 55→    border: none;
 56→    cursor: pointer;
 57→    padding: 0;
 58→    transition: background 0.1s ease;
 59→}
 60→.cv-back-btn:hover {
 61→    background: var(--bg-hover);
 62→}
 63→.cv-back-btn svg {
 64→    width: 18px;
 65→    height: 18px;
 66→    fill: var(--text-secondary);
 67→}
 68→.cv-header-label {
 69→    font-family: var(--font-ui);
 70→    font-size: 0.875rem;
 71→    font-weight: 500;
 72→    color: var(--text-secondary);
 73→    margin: 0;
 74→    padding: 0;
 75→}
 76→
 77→/* ── Article wrapper ── */
 78→.cv-article {
 79→    max-width: 620px;
 80→    width: 100%;
 81→    padding: 0 24px;
 82→    box-sizing: border-box;
 83→}
 84→
 85→/* ── Title ── */
 86→.cv-title {
 87→    margin: 80px 0 0 0;
 88→    padding: 0;
 89→    font-family: var(--font-serif);
 90→    font-size: 2.5rem;
 91→    font-weight: 700;
 92→    color: var(--text-heading);
 93→    line-height: 1.2;
 94→    letter-spacing: -0.01em;
 95→}
 96→
 97→/* ── Metadata ── */
 98→.cv-meta {
 99→    display: flex;
100→    align-items: flex-start;
101→    gap: 10px;
102→    margin-top: 24px;
103→    padding: 0;
104→}
105→.cv-avatar-wrap {
106→    flex-shrink: 0;
107→    display: flex;
108→    justify-content: center;
109→    align-items: center;
110→    border-radius: 50%;
111→    cursor: pointer;
112→}
113→.cv-avatar-wrap.cv-avatar-ring-legend {
114→    border: 2px solid #FFD700;
115→    box-shadow: 0 0 8px 1px rgba(255, 215, 0, 0.3);
116→}
117→.cv-avatar-wrap.cv-avatar-ring-og {
118→    border: 2px solid #9B59FF;
119→    box-shadow: 0 0 8px 1px rgba(155, 89, 255, 0.3);
120→}
121→.cv-avatar {
122→    width: 36px;
123→    height: 36px;
124→    border-radius: 50%;
125→    object-fit: cover;
126→}
127→.cv-meta-info {
128→    display: flex;
129→    flex-direction: column;
130→    gap: 2px;
131→    min-width: 0;
132→}
133→.cv-meta-top {
134→    display: flex;
135→    align-items: center;
136→    gap: 6px;
137→    flex-wrap: wrap;
138→}
139→.cv-author-name {
140→    font-family: var(--font-ui);
141→    font-size: 0.875rem;
142→    font-weight: 500;
143→    color: var(--text-secondary);
144→    cursor: pointer;
145→    transition: color 0.1s ease;
146→    margin: 0;
147→    padding: 0;
148→}
149→.cv-author-name:hover {
150→    color: var(--text-primary);
151→}
152→.cv-follow-btn {
153→    font-family: var(--font-ui);
154→    font-size: 0.8125rem;
155→    font-weight: 500;
156→    color: var(--accent-purple);
157→    background: none;
158→    border: none;
159→    padding: 0;
160→    cursor: pointer;
161→    user-select: none;
162→    transition: text-decoration 0.1s ease;
163→}
164→.cv-follow-btn:hover {
165→    text-decoration: underline;
166→}
167→.cv-follow-btn--following {
168→    color: var(--text-muted);
169→}
170→.cv-follow-btn--following:hover {
171→    color: rgb(220, 80, 80);
172→    text-decoration: none;
173→}
174→.cv-meta-bottom {
175→    display: flex;
176→    align-items: center;
177→    gap: 6px;
178→}
179→.cv-date,
180→.cv-read-time {
181→    font-family: var(--font-ui);
182→    font-size: 0.8125rem;
183→    font-weight: 400;
184→    color: var(--text-muted);
185→    margin: 0;
186→    padding: 0;
187→}
188→.cv-meta-dot {
189→    font-size: 0.8125rem;
190→    color: var(--text-muted);
191→}
192→
193→/* ── Action bar ── */
194→.cv-actions {
195→    display: flex;
196→    align-items: center;
197→    gap: 4px;
198→    margin-top: 20px;
199→    padding: 8px 0;
200→    border-top: 1px solid var(--border-light);
201→}
202→.cv-action-btn {
203→    display: inline-flex;
204→    align-items: center;
205→    gap: 4px;
206→    padding: 4px 8px;
207→    border-radius: 4px;
208→    border: none;
209→    background: transparent;
210→    cursor: pointer;
211→    transition: background 0.1s ease;
212→    font-family: var(--font-ui);
213→    font-size: 0.8125rem;
214→    font-weight: 400;
215→    color: var(--text-muted);
216→}
217→.cv-action-btn:hover {
218→    background: var(--bg-hover);
219→}
220→.cv-action-btn svg {
221→    width: 18px;
222→    height: 18px;
223→    flex-shrink: 0;
224→}
225→.cv-action-btn--end {
226→    margin-left: auto;
227→}
228→
229→/* ── Body content (Lexical) ── */
230→.cv-body {
231→    margin-top: 32px;
232→    margin-bottom: 80px;
233→    font-family: var(--font-serif);
234→    font-size: 1.125rem;
235→    font-weight: 400;
236→    color: var(--text-primary);
237→    line-height: 1.8;
238→    letter-spacing: -0.003em;
