276→
277→
278→.cv-remix-btn{
279→    border: 1px solid color-mix(in srgb, var(--accent-purple) 42%, var(--border-card));
280→    background: var(--bg-secondary);
281→    color: var(--accent-purple);
282→    border-radius: 999px;
