  1→/* ─── Reaction Picker ─── */
  2→.reaction-picker {
  3→    position: absolute;
  4→    bottom: calc(100% + 8px);
  5→    left: calc(50% + 2rem);
  6→    display: flex;
  7→    gap: 4px;
  8→    padding: 6px 10px;
  9→    background: var(--card-bg, rgba(30, 30, 30, 0.95));
 10→    border: 1px solid var(--border-color, rgba(255, 255, 255, 0.12));
 11→    border-radius: 24px;
 12→    backdrop-filter: blur(16px);
 13→    -webkit-backdrop-filter: blur(16px);
 14→    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.3);
 15→    z-index: 200;
 16→    white-space: nowrap;
 17→}
 18→
 19→.reaction-picker::after {
 20→    content: '';
 21→    position: absolute;
 22→    bottom: -12px;
 23→    left: 0;
 24→    right: 0;
 25→    height: 12px;
 26→}
 27→
 28→.reaction-picker-item {
 29→    background: none;
 30→    border: none;
 31→    font-size: 22px;
 32→    cursor: pointer;
 33→    padding: 4px 6px;
 34→    border-radius: 8px;
 35→    transition: background 0.15s ease;
 36→    line-height: 1;
 37→}
 38→
 39→.reaction-picker-item:hover {
 40→    background: rgba(255, 255, 255, 0.1);
 41→}
 42→
 43→.reaction-picker-item.is-active {
 44→    background: rgba(255, 255, 255, 0.15);
 45→}
 46→
 47→/* ─── Reaction Button ─── */
 48→.reaction-button-container {
 49→    position: relative;
 50→    display: inline-flex;
 51→    align-items: center;
 52→    gap: 4px;
 53→}
 54→
 55→.reaction-button {
 56→    display: flex;
 57→    align-items: center;
 58→    justify-content: center;
 59→    cursor: pointer;
 60→    transition: transform 0.15s ease;
 61→}
 62→
 63→.reaction-button:active {
 64→    transform: scale(0.9);
 65→}
 66→
 67→.reaction-button-emoji {
 68→    font-size: 18px;
 69→    line-height: 1;
 70→}
 71→
 72→.reaction-count {
 73→    font-size: 0.78rem;
 74→    padding: 0;
 75→    margin: 0;
 76→    color: var(--text-secondary, #a1a1aa);
 77→}
 78→
 79→/* ─── Reaction Summary (ContentView) ─── */
 80→.reaction-summary {
 81→    display: flex;
 82→    flex-wrap: wrap;
 83→    gap: 8px;
 84→    padding: 8px 0;
 85→}
 86→
 87→.reaction-summary-chip {
 88→    display: inline-flex;
 89→    align-items: center;
 90→    gap: 4px;
 91→    padding: 4px 10px;
 92→    border-radius: 16px;
 93→    background: var(--card-bg, rgba(255, 255, 255, 0.05));
 94→    border: 1px solid var(--border-color, rgba(255, 255, 255, 0.08));
 95→    font-size: 13px;
 96→}
 97→
 98→.reaction-summary-emoji {
 99→    font-size: 15px;
100→    line-height: 1;
101→}
102→
103→.reaction-summary-count {
104→    color: var(--text-secondary, #a1a1aa);
105→    font-weight: 500;
106→    font-variant-numeric: tabular-nums;
107→}
108→
109→/* ─── Mobile: scale down picker to fit viewport ─── */
110→@media (max-width: 480px) {
111→    .reaction-picker {
112→        left: -22px;
113→        gap: 2px;
114→        padding: 5px 6px;
115→    }
116→    .reaction-picker-item {
117→        font-size: 18px;
118→        padding: 3px 4px;
119→    }
120→}
