  1→import React, { useState, useRef, useCallback, useEffect } from 'react';
  2→import ReactionPicker from './ReactionPicker';
  3→import { getReactionEmoji } from '../../utils/reactionConfig';
  4→import './reactions.css';
  5→
  6→const ReactionButton = ({ userReaction, reactionCount, onReact, disabled }) => {
  7→    const [showPicker, setShowPicker] = useState(false);
  8→    const hoverTimerRef = useRef(null);
  9→    const leaveTimerRef = useRef(null);
 10→    const longPressTimerRef = useRef(null);
 11→    const longPressOpenedRef = useRef(false);
 12→    const isTouchRef = useRef(false);
 13→    const containerRef = useRef(null);
 14→
 15→    const handleMouseEnter = useCallback(() => {
 16→        if (isTouchRef.current) return;
 17→        if (leaveTimerRef.current) {
 18→            clearTimeout(leaveTimerRef.current);
 19→            leaveTimerRef.current = null;
 20→        }
 21→        hoverTimerRef.current = setTimeout(() => {
 22→            setShowPicker(true);
 23→        }, 300);
 24→    }, []);
 25→
 26→    const handleMouseLeave = useCallback(() => {
 27→        if (isTouchRef.current) return;
 28→        if (hoverTimerRef.current) {
 29→            clearTimeout(hoverTimerRef.current);
 30→            hoverTimerRef.current = null;
 31→        }
 32→        leaveTimerRef.current = setTimeout(() => {
 33→            setShowPicker(false);
 34→        }, 150);
 35→    }, []);
 36→
 37→    const handleTouchStart = useCallback(() => {
 38→        isTouchRef.current = true;
 39→        longPressTimerRef.current = setTimeout(() => {
 40→            longPressOpenedRef.current = true;
 41→            setShowPicker(true);
 42→        }, 500);
 43→    }, []);
 44→
 45→    const handleTouchEnd = useCallback(() => {
 46→        if (longPressTimerRef.current) {
 47→            clearTimeout(longPressTimerRef.current);
 48→            longPressTimerRef.current = null;
 49→        }
 50→    }, []);
 51→
 52→    // Tap-outside-to-close for mobile
 53→    useEffect(() => {
 54→        if (!showPicker || !isTouchRef.current) return;
 55→
 56→        const handleOutsideTouch = (e) => {
 57→            if (containerRef.current && !containerRef.current.contains(e.target)) {
 58→                setShowPicker(false);
 59→                isTouchRef.current = false;
 60→            }
 61→        };
 62→
 63→        document.addEventListener('touchstart', handleOutsideTouch);
 64→        return () => document.removeEventListener('touchstart', handleOutsideTouch);
 65→    }, [showPicker]);
 66→
 67→    useEffect(() => {
 68→        return () => {
 69→            if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
 70→            if (leaveTimerRef.current) clearTimeout(leaveTimerRef.current);
 71→            if (longPressTimerRef.current) clearTimeout(longPressTimerRef.current);
