128→                        <path id="rec" d="M2.18005 10.6199C2.18005 10.03 2.62777 9.55176 3.18005 9.55176H6.68005C7.23234 9.55176 7.68005 10.03 7.68005 10.6199V21.3018H3.18005C2.62777 21.3018 2.18005 20.8235 2.18005 20.2336V10.6199Z" fill="var(--icon-default)"/>
129→                        </g>
130→                        </g>
131→                    </svg>
132→                )}
133→            </div>
134→            {typeof reactionCount === 'number' && reactionCount > 0 && (
